-- Migration: persist SSH host public keys so leasing/teardown can pin them.
--
-- Every host key in the imbue_cloud stack is already generated by us at bake
-- time (container keys via the vps_docker bake, VPS/VM-root keys via cloud-init
-- or the lima YAML, and -- once the matching code lands -- the bare-metal box
-- key injected during OVH reinstall). Persisting the PUBLIC halves lets the
-- lease client and the connector pin them with strict host-key checking instead
-- of trust-on-first-use:
--
--  * pool_hosts.outer_host_public_key  -- the VPS/VM-root sshd host key (port
--    ``ssh_port``); the connector pins it when injecting the user's key, and the
--    slow-path rebuild pins it for its outer connection.
--  * pool_hosts.container_host_public_key -- the docker container sshd host key
--    (port ``container_ssh_port``); the connector pins it when injecting the
--    user's key, and the fast/adopt path pins it for the agent connection.
--  * bare_metal_servers.box_host_public_key -- the bare-metal box's sshd host
--    key (port 22); admin tooling, the lima slice client, and the connector's
--    slice teardown pin it.
--
-- All three are PUBLIC keys only. They are NULL for any row created before this
-- migration; a one-time ``mngr imbue_cloud admin`` keyscan backfill populates
-- the existing rows, after which leasing/teardown enforce strict pinning.
--
-- Apply with:
--     psql "$NEON_DB_DIRECT" -f apps/remote_service_connector/migrations/011_host_public_keys.sql
--
-- No IF NOT EXISTS guard: schema_migrations is the source of truth for which
-- migrations have run.

BEGIN;

ALTER TABLE pool_hosts ADD COLUMN outer_host_public_key TEXT;
ALTER TABLE pool_hosts ADD COLUMN container_host_public_key TEXT;
ALTER TABLE bare_metal_servers ADD COLUMN box_host_public_key TEXT;

COMMIT;
